// scripts/snapshot-design-references.mjs
// Captures PNG snapshots of every key Empress Health page to
// design-references/screenshots/.
//
// Run via: npm run design:snapshot
// Requires: server running on http://localhost:3100 (or override with
// DESIGN_SNAPSHOT_BASE env var)
//
// Generated by the `design-ready` skill. Add pages by editing PAGES below.

import { chromium } from "playwright";
import fs from "node:fs/promises";
import path from "node:path";

const BASE_URL = process.env.DESIGN_SNAPSHOT_BASE || "http://localhost:3100";
const OUT_DIR  = path.resolve("design-references/screenshots");

// route + name + fullPage decision per surface.
// Order matches the user journey: marketing → onboarding → product → community.
const PAGES = [
  // Marketing & content
  { route: "/",                    name: "00-home",                 fullPage: true  },
  { route: "/howitworks",          name: "01-how-it-works",         fullPage: true  },
  { route: "/whyempresshealth",    name: "02-why-empress",          fullPage: true  },
  { route: "/founderstory",        name: "03-founder-story",        fullPage: true  },
  { route: "/ourstory",            name: "04-our-story",            fullPage: true  },
  { route: "/team",                name: "05-team",                 fullPage: true  },
  { route: "/faq",                 name: "06-faq",                  fullPage: true  },
  { route: "/contact",             name: "07-contact",              fullPage: true  },

  // Membership flow
  { route: "/signup",              name: "10-signup",               fullPage: true  },
  { route: "/login",               name: "11-login",                fullPage: true  },
  { route: "/membershipoptions",   name: "12-membership-options",   fullPage: true  },
  { route: "/membershipsurvey",    name: "13-membership-survey",    fullPage: true  },

  // Assessment SPA + report
  { route: "/assessment?debug=1",  name: "20-assessment-debug",     fullPage: true  },

  // Marketplace
  { route: "/bundlesandkits",      name: "30-bundles-and-kits",     fullPage: true  },
  { route: "/supplements",         name: "31-supplements",          fullPage: true  },
  { route: "/skincare",            name: "32-skincare",             fullPage: true  },
  { route: "/haircare",            name: "33-haircare",             fullPage: true  },
  { route: "/selfcaretools",       name: "34-selfcare-tools",       fullPage: true  },

  // Community & content
  { route: "/community",           name: "40-community",            fullPage: true  },
  { route: "/communitystories",    name: "41-community-stories",    fullPage: true  },
  { route: "/expertblogs",         name: "42-expert-blogs",         fullPage: true  },
  { route: "/expertguidance",      name: "43-expert-guidance",      fullPage: true  },
  { route: "/events",              name: "44-events",               fullPage: true  },
  { route: "/ebookguides",         name: "45-ebook-guides",         fullPage: true  },
  { route: "/wellnesshub",         name: "46-wellness-hub",         fullPage: true  },
  { route: "/symptomsupport",      name: "47-symptom-support",      fullPage: true  },
  { route: "/dailyaffirmations",   name: "48-daily-affirmations",   fullPage: true  },
  { route: "/menopausemonth",      name: "49-menopause-month",      fullPage: true  },
  { route: "/askempress",          name: "50-chatbot",              fullPage: true  },

  // Trust & footer-linked
  { route: "/privacypolicy",       name: "90-privacy",              fullPage: true  },
  { route: "/cookies",             name: "91-cookies",              fullPage: true  },
  { route: "/accessibility",       name: "92-accessibility",        fullPage: true  },
];

// Desktop 1440×900 + mobile 375×812. Each page gets both.
const VIEWPORTS = [
  { suffix: "-desktop", width: 1440, height: 900,  device: 2 },
  { suffix: "-mobile",  width: 375,  height: 812,  device: 2 },
];

async function main() {
  await fs.mkdir(OUT_DIR, { recursive: true });

  // Quick reachability check — fail fast if server is down.
  try {
    const probe = await fetch(BASE_URL + "/api/health", { signal: AbortSignal.timeout(3000) });
    if (!probe.ok) throw new Error(`/api/health returned ${probe.status}`);
  } catch (err) {
    console.error(`\n  ❌ Server not reachable at ${BASE_URL}`);
    console.error(`     Boot it with:\n        PORT=3100 SESSION_SECRET=dev MOCK_LLM=1 node server.js`);
    console.error(`     (or override the base URL via DESIGN_SNAPSHOT_BASE=...)\n`);
    process.exit(2);
  }

  console.log(`\n  → capturing ${PAGES.length} pages × ${VIEWPORTS.length} viewports = ${PAGES.length * VIEWPORTS.length} screenshots`);
  console.log(`  → base URL: ${BASE_URL}`);
  console.log(`  → output:   ${OUT_DIR}\n`);

  const browser = await chromium.launch({ headless: true, args: ["--no-sandbox", "--disable-dev-shm-usage"] });
  let captured = 0;
  let failed = 0;

  try {
    for (const page of PAGES) {
      for (const vp of VIEWPORTS) {
        const ctx = await browser.newContext({
          viewport: { width: vp.width, height: vp.height },
          deviceScaleFactor: vp.device,
          reducedMotion: "reduce",
        });
        const tab = await ctx.newPage();
        try {
          const url = `${BASE_URL}${page.route}`;
          await tab.goto(url, { waitUntil: "networkidle", timeout: 30000 });
          await tab.waitForTimeout(800); // let deferred animations settle
          const out = path.join(OUT_DIR, `${page.name}${vp.suffix}.png`);
          await tab.screenshot({ path: out, fullPage: page.fullPage });
          console.log(`  ✓ ${(page.name + vp.suffix).padEnd(38)} → ${path.relative(process.cwd(), out)}`);
          captured++;
        } catch (err) {
          console.warn(`  ✗ ${(page.name + vp.suffix).padEnd(38)} failed: ${err.message}`);
          failed++;
        } finally {
          await ctx.close();
        }
      }
    }
  } finally {
    await browser.close();
  }

  console.log(`\n  ${captured} captured, ${failed} failed.\n  Output: ${OUT_DIR}\n`);
  process.exit(failed > 0 ? 1 : 0);
}

main().catch((err) => {
  console.error("snapshot failed:", err);
  process.exit(1);
});
